import { randomBytes, createHash } from "crypto";

type Strength = "standard" | "strong" | "maximum";

type ObfuscateOptions = {
  strength?: Strength;
  profileId?: string;
  scriptId?: string;
  antiTamper?: boolean;
  antiDebug?: boolean;
  antiHook?: boolean;
  antiDump?: boolean;
  antiDecompile?: boolean;
  antiEnv?: boolean;
  antiEmulation?: boolean;
  antiPatch?: boolean;
  antiVm?: boolean;
  antiSpoof?: boolean;
  antiReplay?: boolean;
  antiKeySharing?: boolean;
  antiHwidSpoof?: boolean;
  antiBypass?: boolean;
  integrity?: boolean;
  obfuscation?: boolean;
  controlFlow?: boolean;
  stringEncryption?: boolean;
  runtimeChecks?: boolean;
  expectedExecutors?: string[];
  expectedPlaceIds?: number[];
  expectedUniverseIds?: number[];
};

const BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

export function isLoadStringPayload(source: string) {
  // Detect already-obfuscated code by looking for the characteristic variable patterns
  // Must have BOTH the obfuscated chunk table AND the loadstring execution pattern
  return source.includes("_r=") && source.includes("loadstring or load") && source.includes("FireLabPayload");
}

function shuffleAlphabet(): string {
  const chars = BASE64_ALPHABET.split("");
  for (let i = chars.length - 1; i > 0; i--) {
    const j = randomBytes(1)[0] % (i + 1);
    [chars[i], chars[j]] = [chars[j], chars[i]];
  }
  return chars.join("");
}

function encodeCustomBase64(bytes: number[], alphabet: string): string {
  let output = "";
  for (let i = 0; i < bytes.length; i += 3) {
    const first = bytes[i];
    const second = bytes[i + 1] ?? 0;
    const third = bytes[i + 2] ?? 0;
    output += alphabet[(first >> 2) & 0x3f];
    output += alphabet[((first & 0x03) << 4) | ((second >> 4) & 0x0f)];
    output += i + 1 < bytes.length ? alphabet[((second & 0x0f) << 2) | ((third >> 6) & 0x03)] : "=";
    output += i + 2 < bytes.length ? alphabet[third & 0x3f] : "=";
  }
  return output;
}

function chunkString(value: string, size: number): string[] {
  const chunks: string[] = [];
  for (let i = 0; i < value.length; i += size) {
    chunks.push(value.slice(i, i + size));
  }
  return chunks;
}

function randomVar(prefix: string): string {
  return `_${prefix}_${randomBytes(3).toString("hex")}`;
}

// Strong obfuscation: multi-layer XOR + byte rotation + custom base64 + variable randomization
export function obfuscateLua(source: string, options: ObfuscateOptions = {}): string {
  if (!source.trim()) return source;
  if (isLoadStringPayload(source)) return source;

  const strength = options.strength ?? "strong";
  const keyLength = strength === "maximum" ? 32 : strength === "strong" ? 24 : 16;
  const rawKey = randomBytes(keyLength);
  const alphabet = shuffleAlphabet();
  const rotation = randomBytes(1)[0] % 255 || 1;

  // Layer 1: XOR with key
  const sourceBytes = Array.from(Buffer.from(source, "utf8"));
  const xoredBytes = sourceBytes.map((byte, i) => (byte ^ rawKey[i % rawKey.length]) & 0xff);

  // Layer 2: Byte rotation (add rotation value)
  const rotatedBytes = xoredBytes.map(byte => (byte + rotation) & 0xff);

  // Layer 3: Custom base64 encode
  const encoded = encodeCustomBase64(rotatedBytes, alphabet);
  const keyHex = rawKey.toString("hex");
  const checksum = createHash("sha256").update(encoded + keyHex + rotation).digest("hex").slice(0, 16);
  const chunks = chunkString(encoded, 80);

  // Randomized variable names
  const v = {
    chunks: randomVar("c"),
    key: randomVar("k"),
    alphabet: randomVar("a"),
    expected: randomVar("e"),
    idx: randomVar("i"),
    decode: randomVar("d"),
    unkey: randomVar("u"),
    hex: randomVar("h"),
    encoded: randomVar("en"),
    decoded: randomVar("de"),
    fn: randomVar("f"),
    execute: randomVar("x"),
    chunks2: randomVar("c2"),
    srcLen: randomVar("sl"),
  };

  return `local ${v.chunks}={${chunks.map(c => `[==[${c}]==]`).join(",")}}
local ${v.key}="${keyHex}"
local ${v.alphabet}="${alphabet}"
local ${v.expected}="${checksum}"
local _r=${rotation}
local ${v.srcLen}=${sourceBytes.length}
local ${v.idx}={}
for _i=1,#${v.alphabet} do ${v.idx}[${v.alphabet}:sub(_i,_i)]=_i-1 end
local function ${v.decode}(_chunk)
  local _cl=_chunk:gsub("[^"..${v.alphabet}.."=]","")
  local _o={}
  for _i=1,#_cl,4 do
    local _q=_cl:sub(_i,_i+3)
    local _a=${v.idx}[_q:sub(1,1)]
    local _b=${v.idx}[_q:sub(2,2)]
    if not _a or not _b then error("E1") end
    local _c=${v.idx}[_q:sub(3,3)]
    local _d=${v.idx}[_q:sub(4,4)]
    if _q:sub(4,4)=="=" then
      if _q:sub(3,3)=="=" then
        _o[#_o+1]=(_a*4+math.floor(_b/16))%256
      else
        if not _c then error("E2") end
        _o[#_o+1]=(_a*4+math.floor(_b/16))%256
        _o[#_o+1]=((_b%16)*16+math.floor(_c/4))%256
      end
    else
      if not _c or not _d then error("E3") end
      _o[#_o+1]=(_a*4+math.floor(_b/16))%256
      _o[#_o+1]=((_b%16)*16+math.floor(_c/4))%256
      _o[#_o+1]=((_c%4)*64+_d)%256
    end
  end
  return _o
end
local function ${v.unkey}(_bytes,_key,_rot,_srcLen)
  local _o={}
  local _kb={}
  for _i=1,#_key,2 do
    _kb[#_kb+1]=tonumber(_key:sub(_i,_i+1),16)
  end
  local _max=math.min(#_bytes,_srcLen)
  for _i=1,_max do
    local _byte=(_bytes[_i]-_rot)%256
    _byte=(_byte ~ _kb[((_i-1)%#_kb)+1])&0xFF
    _o[_i]=string.char(_byte)
  end
  return table.concat(_o)
end
local ${v.encoded}=""
for _i=1,#${v.chunks} do ${v.encoded}=${v.encoded}..${v.chunks}[_i] end
local ${v.decoded}=${v.unkey}(${v.decode}(${v.encoded}),${v.key},_r,${v.srcLen})
local ${v.fn}=loadstring or load
local ${v.execute}=${v.fn}(${v.decoded},"FireLabPayload")
if ${v.execute} then ${v.execute}() else error("E4") end
`;
}

// Generate a loadstring wrapper that fetches from the API
export function generateLoadString(config: {
  gatewayUrl: string;
  scriptId: string;
  apiSecret?: string;
  encryptionKey: string;
  keyless?: boolean;
  getKeyLink?: string;
}): string {
  const scriptId = config.scriptId;
  const gateway = config.gatewayUrl;
  const encKey = config.encryptionKey;
  const apiSecret = config.apiSecret || "";
  const keyless = config.keyless || false;
  const getKeyLink = config.getKeyLink || "";

  return `--[[
    FireLab Script Shield — Loadstring v2.0
    Script ID: ${scriptId}
    ${keyless ? "Mode: Keyless (no key required)" : "Mode: Key required"}
    ${getKeyLink ? "Get Key: " + getKeyLink : ""}

    HOW TO USE:
    1. Paste this entire script into your executor
    2. ${keyless ? "Press Execute — no key needed!" : 'Set your key: script_key = "YOUR-KEY-HERE"'}
    3. Press Execute
]]

${keyless ? "" : 'script_key = script_key or ""'} -- ${keyless ? "Keyless mode" : "Replace with your key or leave empty for prompt"}

-- Do not edit below this line
local _GATEWAY = "${gateway}"
local _SCRIPT_ID = "${scriptId}"
local _ENC_KEY = "${encKey}"
local _API_SECRET = "${apiSecret}"
local _KEYLESS = ${keyless ? "true" : "false"}
local _GET_KEY = "${getKeyLink}"
local _VERSION = "2.0.0"

local function _kick(msg)
    local g = game
    if g and g.Kick then pcall(g.Kick, g, "[FireLab] " .. tostring(msg)) end
end

local function _hwid()
    if gethwid then return gethwid() end
    if syn and syn.get_hwid then return syn.get_hwid() end
    if fluxus and fluxus.get_hwid then return fluxus.get_hwid() end
    if evon and evon.get_hwid then return evon.get_hwid() end
    if krnl and krnl.get_hwid then return krnl.get_hwid() end
    return "unknown:" .. tostring(os.clock())
end

local function _executor()
    if getexecutorname then return getexecutorname() end
    if identifyexecutor then return identifyexecutor() end
    return "UnknownExecutor"
end

local function _json(str)
    if not str then return {} end
    local o = {}
    for k, v in str:gmatch('"([^"]+)"%s*:%s*"([^"]*)"') do o[k] = v end
    for k, v in str:gmatch('"([^"]+)"%s*:%s*(%-?%d+)') do o[k] = tonumber(v) end
    for k in str:gmatch('"([^"]+)"%s*:%s*(true)') do o[k] = true end
    for k in str:gmatch('"([^"]+)"%s*:%s*(false)') do o[k] = false end
    return o
end

local function _esc(s)
    s = s:gsub("\\\\", "\\\\\\\\")
    s = s:gsub('"', '\\\\"')
    s = s:gsub("\\n", "\\\\n")
    s = s:gsub("\\r", "\\\\r")
    s = s:gsub("\\t", "\\\\t")
    return s
end

local function _stringify(t)
    local p = {}
    for _, k in ipairs({"key","hwid","scriptId","nonce","timestamp","executor"}) do
        if t[k] ~= nil then p[#p+1] = '"'..k..'":"'.._esc(tostring(t[k]))..'"' end
    end
    return "{" .. table.concat(p, ",") .. "}"
end

local function _hmac(body, secret)
    if not secret or secret == "" then return nil end
    if crypt and crypt.hmac then return crypt.hmac("sha256", secret, body) end
    return nil
end

local function _http(url, payload, headers)
    local fn = syn and syn.request or request or http_request
    if not fn then error("[FireLab] No HTTP support") end
    local opts = {Url = url, Method = "POST", Headers = headers, Body = payload}
    local ok, res = pcall(fn, opts)
    if not ok then
        opts = {url = url, method = "POST", headers = headers, body = payload}
        ok, res = pcall(fn, opts)
        if not ok then error("[FireLab] HTTP failed") end
    end
    local body = res.Body or res.body or res.Content or res.content or ""
    local status = res.StatusCode or res.statusCode or res.Status or res.status or 200
    return body, status
end

local function _decrypt(enc, key)
    if not crypt or not crypt.aes then error("[FireLab] No AES support") end
    local parts = {}
    for part in enc:gmatch("[^%.]+") do parts[#parts+1] = part end
    if #parts < 3 then error("[FireLab] Bad payload") end
    local iv, ct, tag = parts[1], parts[2], parts[3]
    local ok, dec = pcall(crypt.aes.decrypt, ct, key, iv, "GCM", tag)
    if ok and dec and dec ~= "" then return dec end
    ok, dec = pcall(crypt.aes.decrypt, ct, key, iv, tag, "GCM")
    if ok and dec and dec ~= "" then return dec end
    error("[FireLab] Decrypt failed")
end

local function _saveKey(key)
    pcall(function() if writefile then writefile("FireLabKey.txt", key) end end)
end

local function _loadKey()
    local key = nil
    pcall(function()
        if readfile and isfile then
            if isfile("FireLabKey.txt") then
                key = readfile("FireLabKey.txt")
                key = key and key:match("^%s*(.-)%s*$")
            end
        end
    end)
    return key
end

local function _clearKey()
    pcall(function() if delfile then delfile("FireLabKey.txt") end end)
end

