// Backward compat
export function obfuscateLuaToLoadString(source: string, options: ObfuscateOptions = {}): string {
  return obfuscateLua(source, options);
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { createAuditLog } from "@/lib/audit-logger";
import { decryptObject, encryptObject, hashString } from "@/lib/crypto";
import { obfuscateLuaToLoadString } from "@/lib/obfuscator";
import { getAuthenticatedUser, getJson, rateLimit } from "@/lib/http";
import { z } from "zod";

const scriptSchema = z.object({
  name: z.string().min(2).max(80),
  description: z.string().max(500).optional(),
  version: z
    .string()
    .regex(/^\d+\.\d+\.\d+$/)
    .optional()
    .default("1.0.0"),
  content: z.string().min(1).max(5_000_000),
  obfuscate: z.boolean().optional().default(true),
  visibility: z
    .enum(["PUBLIC", "PRIVATE", "OBFUSCATED"])
    .optional()
    .default("PRIVATE"),
  status: z
    .enum(["ACTIVE", "MAINTENANCE", "DISABLED"])
    .optional()
    .default("ACTIVE"),
  category: z.string().max(50).optional().default("General"),
  iconUrl: z.string().url().optional(),
  getKeyLink: z.string().max(500).optional().nullable(),
  keyMode: z.enum(["normal", "premium", "keyless"]).optional().default("normal"),
  channel: z.enum(["STABLE", "BETA"]).optional().default("STABLE"),
  protectionProfileId: z.string().uuid().optional().nullable(),
  teamId: z.string().uuid().optional().nullable(),
});

function sanitizeScript(script: any) {
  const content = decryptObject<{ key: string }>(script.contentEncrypted).key;
  return {
    ...script,
    content,
    obfuscatedContent:
      script.visibility === "OBFUSCATED"
        ? obfuscateLuaToLoadString(content)
        : content,
    contentEncrypted: undefined,
    contentHash: undefined,
  };
}

export async function GET(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`scripts:list:${user.id}`, 60, 60 * 1000);
  if (!limited.success) {
    return NextResponse.json(
      { error: "Too many requests" },
      {
        status: 429,
        headers: { "X-RateLimit-Reset": limited.reset.toString() },
      },
    );
  }

  const { searchParams } = new URL(req.url);
  const page = Math.max(Number(searchParams.get("page") || 1), 1);
  const take = Math.min(Number(searchParams.get("take") || 20), 100);
  const search = searchParams.get("search") || "";
  const status = searchParams.get("status") as
    | "ACTIVE"
    | "MAINTENANCE"
    | "DISABLED"
    | undefined;

  const where: any =
    user.role === "ADMIN"
      ? {}
      : {
          OR: [
            { ownerId: user.id },
            { team: { members: { some: { userId: user.id } } } },
          ],
        };
  if (search) where.name = { contains: search, mode: "insensitive" };
  if (status) where.status = status;

  const scripts = await db.script.findMany({
    where,
    include: { owner: { select: { username: true } } },
    orderBy: { createdAt: "desc" },
    skip: (page - 1) * take,
    take,
  });

  return NextResponse.json({
    scripts: scripts.map(sanitizeScript),
    page,
    take,
  });
}

export async function POST(req: Request) {
  const user = await getAuthenticatedUser(req);
  if (!user)
    return NextResponse.json({ error: "Unauthorized" }, { status: 401 });

  const limited = await rateLimit(`scripts:create:${user.id}`, 10, 60 * 1000);
  if (!limited.success)
    return NextResponse.json(
      { error: "Too many script creation attempts" },
      { status: 429 },
    );

  try {
    const body = scriptSchema.safeParse(await getJson(req));
    if (!body.success)
      return NextResponse.json(
        { error: "Invalid script payload", details: body.error.flatten() },
        { status: 400 },
      );

    const data = body.data;
    const storedContent = data.obfuscate
      ? obfuscateLuaToLoadString(data.content)
      : data.content;
    const contentEncrypted = encryptObject({ key: storedContent });
    const script = await db.script.create({
      data: {
        name: data.name,
        description: data.description || null,
        version: data.version,
        contentEncrypted,
        contentHash: hashString(storedContent),
        visibility: data.visibility === "PUBLIC" ? "PUBLIC" : (data.obfuscate ? "OBFUSCATED" : data.visibility),
        status: data.status,
        category: data.category,
        iconUrl: data.iconUrl || null,
        getKeyLink: data.getKeyLink || null,
        keyMode: data.keyMode,
        channel: data.channel,
        protectionProfileId: data.protectionProfileId,
        teamId: data.teamId || null,
        ownerId: user.id,
      },
    });

    await createAuditLog(
      user.id,
      "SCRIPT_CREATE",
      {
        scriptId: script.id,
        scriptName: script.name,
        obfuscated: data.obfuscate,
      },
      undefined,
      req.headers.get("user-agent") || undefined,
      "Script",
      script.id,
    );

    return NextResponse.json({
      message: "Script protected successfully",
      script: sanitizeScript(script),
    });
  } catch (error) {
    console.error("POST Script Error:", error);
    return NextResponse.json(
      { error: "Internal Server Error" },
      { status: 500 },
    );
  }
}

import { NextResponse } from "next/server";
import { db } from "@/lib/db";
import { rateLimit } from "@/lib/rate-limit";
import { getRateLimitHeaders } from "@/lib/rate-limit";
import { decryptObject, hashString, hashToken } from "@/lib/crypto";
import { getClientIp, hashIdentifier } from "@/lib/http";
import { recordSecurityFailure } from "@/lib/ip-reputation";
import { sendDiscordLog } from "@/lib/discord-logger";

function parseQuery(url: URL) {
  return {
    key: url.searchParams.get("key") || "",
    hwid: url.searchParams.get("hwid") || "",
    scriptId: url.searchParams.get("scriptId") || "",
    nonce: url.searchParams.get("nonce") || "",
    timestamp: url.searchParams.get("ts") ? Number(url.searchParams.get("ts")) : undefined,
    executor: url.searchParams.get("executor") || "Unknown",
    check: url.searchParams.get("check") === "1",
  };
}

function errorResponse(message: string, status = 401) {
  return new NextResponse(`ERROR: ${message}`, {
    status,
    headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "no-store" },
  });
}

export async function GET(req: Request) {
  return handleAuth(req);
}

export async function POST(req: Request) {
  return handleAuth(req);
}

async function handleAuth(req: Request) {
  const startTime = Date.now();
  const ip = getClientIp(req);
  const url = new URL(req.url);

  const limited = await rateLimit(`script-auth:${ip}`, 30, 60 * 1000);
  if (!limited.success) {
    return errorResponse("Too many requests", 429);
  }

  try {
    let parsed: ReturnType<typeof parseQuery>;

    if (req.method === "GET") {
      parsed = parseQuery(url);
    } else {
      // POST: parse JSON body
      try {
        const rawBody = await req.text();
        const body = JSON.parse(rawBody);
        parsed = {
          key: body.key || "",
          hwid: body.hwid || "",
          scriptId: body.scriptId || "",
          nonce: body.nonce || "",
          timestamp: body.timestamp,
          executor: body.executor || "Unknown",
          check: false,
        };
      } catch {
        // Fallback: try query params
        parsed = parseQuery(url);
      }
    }

    if (!parsed.key || !parsed.hwid || !parsed.scriptId) {
      return errorResponse("Missing required fields", 400);
    }

    const { key, hwid, scriptId, executor } = parsed;
    const fingerprintHash = hashIdentifier(hwid);
    const userAgent = req.headers.get("user-agent") || "LuauEngine";
    const country = req.headers.get("cf-ipcountry") || req.headers.get("x-country") || null;

    async function logAccess(success: boolean, reason: string, licenseId?: string) {
      try {
        await db.scriptAccessLog.create({
          data: { scriptId, licenseId: licenseId || null, userId: null, ip, country, success, reason, createdAt: new Date() },
        });
      } catch {}
      if (!success) {
        try { await recordSecurityFailure(ip, reason); } catch {}
      }
    }

    // Find the script
    const scriptRecord = await db.script.findUnique({
      where: { id: scriptId },
      select: { id: true, name: true, status: true, visibility: true, contentEncrypted: true, version: true, ownerId: true },
    }).catch(() => null);

    if (!scriptRecord) return errorResponse("Script not found", 404);

    if (scriptRecord.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED");
      return errorResponse("Script is disabled", 403);
    }

    // Keyless mode — PUBLIC scripts don't require a license key
    if (scriptRecord.visibility === "PUBLIC") {
      await logAccess(true, "KEYLESS_ACCESS");

      void sendDiscordLog({
        event: "Script Auth — Keyless", key: "KEYLESS", scriptName: scriptRecord.name,
        ip, country, device: userAgent, hwid, success: true, timestamp: new Date().toISOString(),
      });

      const scriptPayload = decryptObject<{ key: string }>(scriptRecord.contentEncrypted).key;
      return new NextResponse(scriptPayload, {
        headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
      });
    }

    // Key-based auth
    const keyHash = hashToken(key);
    const license = await db.license.findUnique({
      where: { keyHash },
      include: { script: { include: { protectionProfile: true } }, hwids: { orderBy: { createdAt: "desc" } } },
    });

    if (!license || license.scriptId !== scriptId) {
      await logAccess(false, "INVALID_LICENSE_OR_SCRIPT_BINDING");
      return errorResponse("Invalid license key or script binding");
    }

    if (license.script.status === "DISABLED") {
      await logAccess(false, "SCRIPT_DISABLED", license.id);
      return errorResponse("Script is disabled", 403);
    }

    // Auto-redeem UNREDEEMED keys on first use
    if (license.status === "UNREDEEMED") {
      let expiresAt: Date | null = null;
      if (license.type === "SUBSCRIPTION" && license.durationDays) {
        expiresAt = new Date(Date.now() + license.durationDays * 24 * 60 * 60 * 1000);
      }
      await db.license.update({
        where: { id: license.id },
        data: { status: "ACTIVE", redeemedAt: new Date(), redeemedBy: hwid, expiresAt },
      }).catch(() => {});
    }

    if (license.status === "SUSPENDED") {
      await logAccess(false, "LICENSE_SUSPENDED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Suspended", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License suspended", timestamp: new Date().toISOString() });
      return errorResponse("License has been suspended", 403);
    }
    if (license.status === "BLACKLISTED") {
      await logAccess(false, "LICENSE_BLACKLISTED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Blacklisted", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License blacklisted", timestamp: new Date().toISOString() });
      return errorResponse("License is blacklisted", 403);
    }
    if (license.status === "EXPIRED" || (license.expiresAt && new Date() > license.expiresAt)) {
      if (license.status !== "EXPIRED") {
        await db.license.update({ where: { id: license.id }, data: { status: "EXPIRED" } });
      }
      await logAccess(false, "LICENSE_EXPIRED", license.id);
      void sendDiscordLog({ event: "Script Auth — Key Expired", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "License expired", timestamp: new Date().toISOString() });
      return errorResponse("License has expired", 403);
    }

    // HWID lock — auto-bind on first use
    let hwidRecord = await db.hwid.findFirst({ where: { licenseId: license.id, fingerprintHash } });
    if (license.hwidLock) {
      if (!hwidRecord && license.hwids.length > 0) {
        await logAccess(false, "HWID_MISMATCH", license.id);
        void sendDiscordLog({ event: "Script Auth — HWID Mismatch", key, scriptName: license.script.name, ip, country, hwid, success: false, reason: "HWID mismatch", timestamp: new Date().toISOString() });
        return errorResponse("HWID mismatch — reset HWID from dashboard");
      }
      if (!hwidRecord) {
        hwidRecord = await db.hwid.create({
          data: { licenseId: license.id, fingerprintHash, source: "auth", lastIp: ip, lastDeviceInfo: userAgent },
        });
      } else {
        await db.hwid.update({ where: { id: hwidRecord.id }, data: { lastIp: ip, lastDeviceInfo: userAgent } });
      }
    }

    // Log the activation
    await db.activation.create({
      data: { licenseId: license.id, hwidId: hwidRecord?.id || null, fingerprintHash, ip, country, deviceInfo: userAgent, userAgent, success: true },
    }).catch(() => {});

    await logAccess(true, "AUTH_SUCCESS", license.id);

    void sendDiscordLog({
      event: "Script Authentication", key, scriptName: license.script.name,
      ip, country, device: userAgent, hwid, success: true, timestamp: new Date().toISOString(),
    });

    const scriptPayload = decryptObject<{ key: string }>(license.script.contentEncrypted).key;

    return new NextResponse(scriptPayload, {
      headers: { "Content-Type": "text/plain; charset=utf-8", "Cache-Control": "private, no-store" },
    });
  } catch (error) {
    console.error("Auth script endpoint error:", error);
    return errorResponse("Internal server error", 500);
  }
}

import { randomBytes, createHash } from "crypto";

type Strength = "standard" | "strong" | "maximum";

type ObfuscateOptions = {
  strength?: Strength;
  profileId?: string;
  scriptId?: string;
  antiTamper?: boolean;
  antiDebug?: boolean;
  antiHook?: boolean;
  antiDump?: boolean;
  antiDecompile?: boolean;
  antiEnv?: boolean;
  antiEmulation?: boolean;
  antiPatch?: boolean;
  antiVm?: boolean;
  antiSpoof?: boolean;
  antiReplay?: boolean;
  antiKeySharing?: boolean;
  antiHwidSpoof?: boolean;
  antiBypass?: boolean;
  integrity?: boolean;
  obfuscation?: boolean;
  controlFlow?: boolean;
  stringEncryption?: boolean;
  runtimeChecks?: boolean;
  expectedExecutors?: string[];
  expectedPlaceIds?: number[];
  expectedUniverseIds?: number[];
};

const BASE64_ALPHABET = "ABCDEFGHIJKLMNOPQRSTUVWXYZabcdefghijklmnopqrstuvwxyz0123456789+/";

export function isLoadStringPayload(source: string) {
  // Detect already-obfuscated code by looking for the characteristic variable patterns
  // Must have BOTH the obfuscated chunk table AND the loadstring execution pattern
  return source.includes("_r=") && source.includes("loadstring or load") && source.includes("FireLabPayload");
}

function shuffleAlphabet(): string {
  const chars = BASE64_ALPHABET.split("");
  for (let i = chars.length - 1; i > 0; i--) {
    const j = randomBytes(1)[0] % (i + 1);
    [chars[i], chars[j]] = [chars[j], chars[i]];
  }
  return chars.join("");
}

function encodeCustomBase64(bytes: number[], alphabet: string): string {
  let output = "";
  for (let i = 0; i < bytes.length; i += 3) {
    const first = bytes[i];
    const second = bytes[i + 1] ?? 0;
    const third = bytes[i + 2] ?? 0;
    output += alphabet[(first >> 2) & 0x3f];
    output += alphabet[((first & 0x03) << 4) | ((second >> 4) & 0x0f)];
    output += i + 1 < bytes.length ? alphabet[((second & 0x0f) << 2) | ((third >> 6) & 0x03)] : "=";
    output += i + 2 < bytes.length ? alphabet[third & 0x3f] : "=";
  }
  return output;
}

function chunkString(value: string, size: number): string[] {
  const chunks: string[] = [];
  for (let i = 0; i < value.length; i += size) {
    chunks.push(value.slice(i, i + size));
  }
  return chunks;
}

function randomVar(prefix: string): string {
  return `_${prefix}_${randomBytes(3).toString("hex")}`;
}

// Strong obfuscation: multi-layer XOR + byte rotation + custom base64 + variable randomization
export function obfuscateLua(source: string, options: ObfuscateOptions = {}): string {
  if (!source.trim()) return source;
  if (isLoadStringPayload(source)) return source;

  const strength = options.strength ?? "strong";
  const keyLength = strength === "maximum" ? 32 : strength === "strong" ? 24 : 16;
  const rawKey = randomBytes(keyLength);
  const alphabet = shuffleAlphabet();
  const rotation = randomBytes(1)[0] % 255 || 1;

  // Layer 1: XOR with key
  const sourceBytes = Array.from(Buffer.from(source, "utf8"));
  const xoredBytes = sourceBytes.map((byte, i) => (byte ^ rawKey[i % rawKey.length]) & 0xff);

  // Layer 2: Byte rotation (add rotation value)
  const rotatedBytes = xoredBytes.map(byte => (byte + rotation) & 0xff);

  // Layer 3: Custom base64 encode
  const encoded = encodeCustomBase64(rotatedBytes, alphabet);
  const keyHex = rawKey.toString("hex");
  const checksum = createHash("sha256").update(encoded + keyHex + rotation).digest("hex").slice(0, 16);
  const chunks = chunkString(encoded, 80);

  // Randomized variable names
  const v = {
    chunks: randomVar("c"),
    key: randomVar("k"),
    alphabet: randomVar("a"),
    expected: randomVar("e"),
    idx: randomVar("i"),
    decode: randomVar("d"),
    unkey: randomVar("u"),
    hex: randomVar("h"),
    encoded: randomVar("en"),
    decoded: randomVar("de"),
    fn: randomVar("f"),
    execute: randomVar("x"),
    chunks2: randomVar("c2"),
    srcLen: randomVar("sl"),
  };

  return `local ${v.chunks}={${chunks.map(c => `[==[${c}]==]`).join(",")}}
local ${v.key}="${keyHex}"
local ${v.alphabet}="${alphabet}"
local ${v.expected}="${checksum}"
local _r=${rotation}
local ${v.srcLen}=${sourceBytes.length}
local ${v.idx}={}
for _i=1,#${v.alphabet} do ${v.idx}[${v.alphabet}:sub(_i,_i)]=_i-1 end
local function ${v.decode}(_chunk)
  local _cl=_chunk:gsub("[^"..${v.alphabet}.."=]","")
  local _o={}
  for _i=1,#_cl,4 do
    local _q=_cl:sub(_i,_i+3)
    local _a=${v.idx}[_q:sub(1,1)]
    local _b=${v.idx}[_q:sub(2,2)]
    if not _a or not _b then error("E1") end
    local _c=${v.idx}[_q:sub(3,3)]
    local _d=${v.idx}[_q:sub(4,4)]
    if _q:sub(4,4)=="=" then
      if _q:sub(3,3)=="=" then
        _o[#_o+1]=(_a*4+math.floor(_b/16))%256
      else
        if not _c then error("E2") end
        _o[#_o+1]=(_a*4+math.floor(_b/16))%256
        _o[#_o+1]=((_b%16)*16+math.floor(_c/4))%256
      end
    else
      if not _c or not _d then error("E3") end
      _o[#_o+1]=(_a*4+math.floor(_b/16))%256
      _o[#_o+1]=((_b%16)*16+math.floor(_c/4))%256
      _o[#_o+1]=((_c%4)*64+_d)%256
    end
  end
  return _o
end
local function ${v.unkey}(_bytes,_key,_rot,_srcLen)
  local _o={}
  local _kb={}
  for _i=1,#_key,2 do
    _kb[#_kb+1]=tonumber(_key:sub(_i,_i+1),16)
  end
  local _max=math.min(#_bytes,_srcLen)
  for _i=1,_max do
    local _byte=(_bytes[_i]-_rot)%256
    _byte=(_byte ~ _kb[((_i-1)%#_kb)+1])&0xFF
    _o[_i]=string.char(_byte)
  end
  return table.concat(_o)
end
local ${v.encoded}=""
for _i=1,#${v.chunks} do ${v.encoded}=${v.encoded}..${v.chunks}[_i] end
local ${v.decoded}=${v.unkey}(${v.decode}(${v.encoded}),${v.key},_r,${v.srcLen})
local ${v.fn}=loadstring or load
local ${v.execute}=${v.fn}(${v.decoded},"FireLabPayload")
if ${v.execute} then ${v.execute}() else error("E4") end
`;
}

// Generate a loadstring wrapper that fetches from the API
export function generateLoadString(config: {
  gatewayUrl: string;
  scriptId: string;
  apiSecret?: string;
  encryptionKey: string;
  keyless?: boolean;
  getKeyLink?: string;
}): string {
  const scriptId = config.scriptId;
  const gateway = config.gatewayUrl;
  const encKey = config.encryptionKey;
  const apiSecret = config.apiSecret || "";
  const keyless = config.keyless || false;
  const getKeyLink = config.getKeyLink || "";

  return `--[[
    FireLab Script Shield — Loadstring v2.0
    Script ID: ${scriptId}
    ${keyless ? "Mode: Keyless (no key required)" : "Mode: Key required"}
    ${getKeyLink ? "Get Key: " + getKeyLink : ""}

    HOW TO USE:
    1. Paste this entire script into your executor
    2. ${keyless ? "Press Execute — no key needed!" : 'Set your key: script_key = "YOUR-KEY-HERE"'}
    3. Press Execute
]]

${keyless ? "" : 'script_key = script_key or ""'} -- ${keyless ? "Keyless mode" : "Replace with your key or leave empty for prompt"}

-- Do not edit below this line
local _GATEWAY = "${gateway}"
local _SCRIPT_ID = "${scriptId}"
local _ENC_KEY = "${encKey}"
local _API_SECRET = "${apiSecret}"
local _KEYLESS = ${keyless ? "true" : "false"}
local _GET_KEY = "${getKeyLink}"
local _VERSION = "2.0.0"

local function _kick(msg)
    local g = game
    if g and g.Kick then pcall(g.Kick, g, "[FireLab] " .. tostring(msg)) end
end

local function _hwid()
    if gethwid then return gethwid() end
    if syn and syn.get_hwid then return syn.get_hwid() end
    if fluxus and fluxus.get_hwid then return fluxus.get_hwid() end
    if evon and evon.get_hwid then return evon.get_hwid() end
    if krnl and krnl.get_hwid then return krnl.get_hwid() end
    return "unknown:" .. tostring(os.clock())
end

local function _executor()
    if getexecutorname then return getexecutorname() end
    if identifyexecutor then return identifyexecutor() end
    return "UnknownExecutor"
end

local function _json(str)
    if not str then return {} end
    local o = {}
    for k, v in str:gmatch('"([^"]+)"%s*:%s*"([^"]*)"') do o[k] = v end
    for k, v in str:gmatch('"([^"]+)"%s*:%s*(%-?%d+)') do o[k] = tonumber(v) end
    for k in str:gmatch('"([^"]+)"%s*:%s*(true)') do o[k] = true end
    for k in str:gmatch('"([^"]+)"%s*:%s*(false)') do o[k] = false end
    return o
end

local function _esc(s)
    s = s:gsub("\\\\", "\\\\\\\\")
    s = s:gsub('"', '\\\\"')
    s = s:gsub("\\n", "\\\\n")
    s = s:gsub("\\r", "\\\\r")
    s = s:gsub("\\t", "\\\\t")
    return s
end

local function _stringify(t)
    local p = {}
    for _, k in ipairs({"key","hwid","scriptId","nonce","timestamp","executor"}) do
        if t[k] ~= nil then p[#p+1] = '"'..k..'":"'.._esc(tostring(t[k]))..'"' end
    end
    return "{" .. table.concat(p, ",") .. "}"
end

local function _hmac(body, secret)
    if not secret or secret == "" then return nil end
    if crypt and crypt.hmac then return crypt.hmac("sha256", secret, body) end
    return nil
end

local function _http(url, payload, headers)
    local fn = syn and syn.request or request or http_request
    if not fn then error("[FireLab] No HTTP support") end
    local opts = {Url = url, Method = "POST", Headers = headers, Body = payload}
    local ok, res = pcall(fn, opts)
    if not ok then
        opts = {url = url, method = "POST", headers = headers, body = payload}
        ok, res = pcall(fn, opts)
        if not ok then error("[FireLab] HTTP failed") end
    end
    local body = res.Body or res.body or res.Content or res.content or ""
    local status = res.StatusCode or res.statusCode or res.Status or res.status or 200
    return body, status
end

local function _decrypt(enc, key)
    if not crypt or not crypt.aes then error("[FireLab] No AES support") end
    local parts = {}
    for part in enc:gmatch("[^%.]+") do parts[#parts+1] = part end
    if #parts < 3 then error("[FireLab] Bad payload") end
    local iv, ct, tag = parts[1], parts[2], parts[3]
    local ok, dec = pcall(crypt.aes.decrypt, ct, key, iv, "GCM", tag)
    if ok and dec and dec ~= "" then return dec end
    ok, dec = pcall(crypt.aes.decrypt, ct, key, iv, tag, "GCM")
    if ok and dec and dec ~= "" then return dec end
    error("[FireLab] Decrypt failed")
end

local function _saveKey(key)
    pcall(function() if writefile then writefile("FireLabKey.txt", key) end end)
end

local function _loadKey()
    local key = nil
    pcall(function()
        if readfile and isfile then
            if isfile("FireLabKey.txt") then
                key = readfile("FireLabKey.txt")
                key = key and key:match("^%s*(.-)%s*$")
            end
        end
    end)
    return key
end

local function _clearKey()
    pcall(function() if delfile then delfile("FireLabKey.txt") end end)
end

