-- Main execution
local _key = script_key or ""
if _KEYLESS then
    _key = "KEYLESS_" .. tostring(os.time())
else
    if _key == "" then _key = _loadKey() or "" end
    if _key == "" then
        local getResult = _keyPrompt()
        local waited = 0
        while not getResult() and waited < 120 do
            if task and task.wait then task.wait(0.5) else wait(0.5) end
            waited = waited + 0.5
        end
        if not getResult() then _kick("Key entry timed out") return end
        _key = getResult()
    end
end

local _hw = _hwid()
local _nonce = tostring(os.time()) .. ":" .. tostring(math.random(1,2147483647))
local _payload = _stringify({
    key = _key, hwid = _hw, scriptId = _SCRIPT_ID,
    nonce = _nonce, timestamp = os.time(), executor = _executor()
})

local _headers = {
    ["Content-Type"] = "application/json",
    ["User-Agent"] = "FireLabLoader/" .. _VERSION,
}
local _sig = _hmac(_payload, _API_SECRET)
if _sig then _headers["X-Signature"] = _sig end

local _body, _status = _http(_GATEWAY, _payload, _headers)

if _status == 401 or _status == 403 then
    local _err = _json(_body)
    _clearKey()
    _kick(_err.error or "Authentication rejected")
    return
end

local _data = _json(_body)
if _data.error then
    _clearKey()
    _kick(tostring(_data.error))
    return
end

local _enc = _data.encrypted_module or ""
if _enc == "" and _data.iv and _data.ciphertext and _data.tag then
    _enc = _data.iv .. "." .. _data.ciphertext .. "." .. _data.tag
end

if _enc ~= "" then
    local _dec = _decrypt(_enc, _ENC_KEY)
    if _dec and _dec ~= "" then
        local _fn = loadstring or load
        local _exec = _fn(_dec, "FireLabPayload")
        if _exec then
            _saveKey(_key)
            _exec()

            -- Runtime check loop
            if _VERSION ~= "" then
                task.spawn(function()
                    while true do
                        task.wait(15)
                        local ok, err = pcall(function()
                            local cp = _stringify({
                                key = _key, hwid = _hwid(), scriptId = _SCRIPT_ID,
                                nonce = tostring(os.time()) .. ":" .. tostring(math.random(1,2147483647)),
                                timestamp = os.time(), executor = _executor()
                            })
                            local ch = {["Content-Type"] = "application/json", ["User-Agent"] = "FireLabChecker/" .. _VERSION}
                            local cs = _hmac(cp, _API_SECRET)
                            if cs then ch["X-Signature"] = cs end
                            local cb, cst = _http(_GATEWAY, cp, ch)
                            if cst == 401 or cst == 403 then
                                _clearKey()
                                _kick(_json(cb).error or "Key invalidated")
                                error("invalid")
                            end
                            local cd = _json(cb)
                            if cd.error then _clearKey() _kick(tostring(cd.error)) error("invalid") end
                        end)
                        if not ok then _kick("Runtime check failed") break end
                    end
                end)
            end
        else
            error("[FireLab] Execution failed")
        end
    else
        error("[FireLab] Decryption failed")
    end
else
    error("[FireLab] No payload")
end
`;
}

// Backward compat
export function obfuscateLuaToLoadString(source: string, options: ObfuscateOptions = {}): string {
